289	// ============== 单位升阶 ==============
290	
291	TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
292	{
293		// 统计每个 TypeID 的出现次数
294		TMap<FName, int32> CountMap;
295	
296		for (const FLFPUnitEntry& Unit : PartyUnits)
297		{
298			if (Unit.IsValid())
299			{
300				CountMap.FindOrAdd(Unit.TypeID, 0)++;
301			}
302		}
303		for (const FLFPUnitEntry& Unit : ReserveUnits)
304		{
305			if (Unit.IsValid())
306			{
307				CountMap.FindOrAdd(Unit.TypeID, 0)++;
308			}
309		}
310	
311		// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
312		TArray<FLFPUnitEntry> Result;
313		for (const auto& Pair : CountMap)
314		{
315			if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
316			{
317				FLFPUnitEntry Entry;
318				Entry.TypeID = Pair.Key;
319				Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
320				Result.Add(Entry);
321			}
322		}
323	
324		return Result;
325	}
326	
327	bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
328		bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
329	{
330		TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
331		TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
332	
333		if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
334		{
335			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
336			return false;
337		}
338	
339		const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
340		const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
341	
342		// 验证两个源单位 TypeID 相同
343		if (UnitA.TypeID != UnitB.TypeID)
344		{
345			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
346				*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
347			return false;
348		}
349	
350		// 验证 TargetTypeID 在进化目标列表中
351		if (!UnitRegistry)
352		{
353			UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
354			return false;
355		}
356	
357		TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
358		if (!Targets.Contains(TargetTypeID))
359		{
360			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
361				*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
362			return false;
363		}
364	
365		// 创建进化后的新单位
366		FLFPUnitEntry NewUnit;
367		NewUnit.TypeID = TargetTypeID;
368		NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
369	
370		// 移除两个源单位（同一数组时先移除大索引避免偏移）
371		if (bSourceAIsParty == bSourceBIsParty)
372		{
373			int32 First = FMath::Max(SourceAIndex, SourceBIndex);
374			int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
375			ArrayA.RemoveAt(First);
376			ArrayA.RemoveAt(Second);
377		}
378		else
379		{
380			ArrayA.RemoveAt(SourceAIndex);
381			ArrayB.RemoveAt(SourceBIndex);
382		}
383	
384		TryAddUnit(NewUnit);
385	
386		UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
387			*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
388	
389		return true;
390	}
