59	void ALFPTurnManager::EndDeploymentPhase()
60	{
61	    UE_LOG(LogTemp, Log, TEXT("布置阶段结束，注册玩家单位"));
62	
63	    // 收集布置阶段放置的玩家单位
64	    TArray<AActor*> FoundActors;
65	    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
66	
67	    for (AActor* Actor : FoundActors)
68	    {
69	        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
70	        {
71	            if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player && !TurnOrderUnits.Contains(Unit))
72	            {
73	                TurnOrderUnits.Add(Unit);
74	            }
75	        }
76	    }
77	
78	    // 开始第一回合
79	    BeginNewRound();
80	}
