82	void ALFPTurnManager::BeginNewRound()
83	{
84	    if (bBattleEnded) return;
85	
86	    CurrentRound++;
87	    bIsInRound = true;
88	
89	    // 重置所有单位
90	    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
91	    {
92	        if (Unit && Unit->IsValidLowLevel())
93	        {
94	            Unit->ResetForNewRound();
95	        }
96	    }
97	
98	    // 按速度排序单位
99	    SortUnitsBySpeed();
100	
101	    // 清空上一轮的敌人计划
102	    EnemyActionPlans.Empty();
103	    AllocatedSkills.Empty();
104	
105	    // 恢复阵营 AP
106	    for (auto& Pair : FactionCurrentAP)
107	    {
108	        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
109	        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
110	    }
111	
112	    // 进入敌人规划阶段
113	    BeginEnemyPlanningPhase();
114	}
