485	        TurnOrderUnits.Remove(Unit);
486	
487	        // 先检查战斗结束条件
488	        CheckBattleEnd();
489	
490	        // 如果战斗未结束且当前单位被移除，传递回合
491	        if (!bBattleEnded && bWasCurrentUnit)
492	        {
