140	void ALFPTacticsUnit::AddCurrentMaxHealth(int32 Delta, bool bKeepHealthRatio)
141	{
142	    const int32 OldMaxHealth = CurrentMaxHealth;
143	    CurrentMaxHealth = FMath::Max(1, CurrentMaxHealth + Delta);
144	    MaxHealth = CurrentMaxHealth;
145	
146	    if (bKeepHealthRatio && OldMaxHealth > 0)
147	    {
148	        const float HealthRatio = static_cast<float>(CurrentHealth) / OldMaxHealth;
149	        CurrentHealth = FMath::Clamp(FMath::RoundToInt(CurrentMaxHealth * HealthRatio), 0, CurrentMaxHealth);
150	    }
151	    else
152	    {
153	        CurrentHealth = FMath::Clamp(CurrentHealth + Delta, 0, CurrentMaxHealth);
154	    }
155	    OnHealthChangedDelegate.Broadcast(CurrentHealth, CurrentMaxHealth);
156	}
