170	void ALFPTacticsUnit::BeginPlay()
171	{
172	    Super::BeginPlay();
173	
174	    if (!bStatsInitialized)
175	    {
176	        if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
177	        {
178	            InitializeFromRegistry(GI->UnitRegistry);
179	        }
180	        else
181	        {
182	            ResetCurrentStatsToBase();
183	        }
184	    }
185	
186	    // 注册到回合管理器
187	    if (ALFPTurnManager* TurnManager = GetTurnManager())
188	    {
189	        TurnManager->RegisterUnit(this);
190	    }
191	
192	    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
193	    {
194	        if (Condition)
195	        {
196	            Condition->RegisterCondition(this);
197	        }
198	    }
199	
200	    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
201	    SetCurrentCoordinates(SpawnPoint);
202	
203		// 初始化血量
204	    CurrentHealth = FMath::Clamp(CurrentHealth, 0, GetCurrentMaxHealth());
205		InitializeHealthBar();
206	
207	    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
208	
209	    // 如果是敌方单位，创建AI控制器
210	    if (IsEnemy())
211	    {
212	        FActorSpawnParameters SpawnParams;
213	        SpawnParams.Owner = this;
214	        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
215	
216	        if (AIControllerClass)
217	        {
218	            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
219	            if (AIController)
220	            {
221	                AIController->Possess(this);
222	                AIController->SetControlledUnit(this);
223	            }
224	        }
225	    }
226	}
