306	bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
307	{
308	    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
309	
310	    ALFPHexGridManager* GridManager = GetGridManager();
311	    if (!GridManager) return false;
312	
313	    // 获取当前所在的格子
314	    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
315	    if (!CurrentTile) return false;
316	
317	    // 寻找路径（FindPath 返回的路径不包含起点）
318	    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
319	    // 计算路径实际移动代价（考虑地形）
320	    int32 PathCost = 0;
321	    for (ALFPHexTile* Tile : MovePath)
322	    {
323	        PathCost += Tile->GetMovementCost();
324	    }
325	    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
326	
327	    // 在路径开头插入当前格子，使 Tick 中 MovePath[0] → MovePath[1] 为第一段移动
328	    MovePath.Insert(CurrentTile, 0);
329	
330	    // 设置移动状态
331	    CurrentTile->SetIsOccupied(false);
332	    TargetTile = NewTargetTile;
333	    CurrentPathIndex = 0;
334	    MoveProgress = 0.0f;
335	    MovementRangeTiles.Empty();
336	
337	    // 启动移动动画（Tick 驱动逐格插值）
338	    bIsMoving = true;
339	
340	    return true;
341	}
