348	void ALFPTacticsUnit::FinishMove()
349	{
350	    bIsMoving = false;
351	
352	    // 更新到目标位置
353	    if (TargetTile)
354	    {
355	        SetCurrentCoordinates(TargetTile->GetCoordinates());
356	        // 计算路径实际移动代价（跳过 MovePath[0] 即起点格子）
357	        int32 TotalCost = 0;
358	        for (int32 i = 1; i < MovePath.Num(); i++)
359	        {
360	            TotalCost += MovePath[i]->GetMovementCost();
361	        }
362	        ConsumeMovePoints(TotalCost);
363	    }
364	
365	    // 清除移动状态
366	    TargetTile = nullptr;
367	    MovePath.Empty();
368	    CurrentPathIndex = -1;
369	    MoveProgress = 0.0f;
370	
371	    // 广播移动完成
372	    OnMoveFinished.Broadcast();
373	}
