511	void ALFPTacticsUnit::Tick(float DeltaTime)
512	{
513	    Super::Tick(DeltaTime);
514	
515	    // 逐格平滑移动
516	    if (bIsMoving && CurrentPathIndex >= 0 && CurrentPathIndex < MovePath.Num() - 1)
517	    {
518	        MoveProgress += MoveSpeed * DeltaTime;
519	
520	        ALFPHexTile* FromTile = MovePath[CurrentPathIndex];
521	        ALFPHexTile* ToTile = MovePath[CurrentPathIndex + 1];
522	
523	        if (FromTile && ToTile)
524	        {
525	            FVector StartPos = FromTile->GetActorLocation() + FVector(0, 0, 1);
526	            FVector EndPos = ToTile->GetActorLocation() + FVector(0, 0, 1);
527	
528	            float Alpha = FMath::Clamp(MoveProgress, 0.f, 1.f);
529	            SetActorLocation(FMath::Lerp(StartPos, EndPos, Alpha));
530	        }
531	
532	        if (MoveProgress >= 1.0f)
533	        {
534	            CurrentPathIndex++;
535	            MoveProgress = 0.0f;
536	
537	            if (CurrentPathIndex >= MovePath.Num() - 1)
538	            {
539	                // 到达终点
540	                FinishMove();
541	            }
542	        }
543	    }
544	}
