560	void ALFPTacticsUnit::TakeDamage(int32 Damage)
561	{
562	    if (bIsDead) return;
563	
564		// 计算实际伤害（考虑防御）
565		int32 ActualDamage = FMath::Max(Damage - GetPhysicalBlock(), 1);
566		CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
567	
568		// 广播血量变化事件
569		OnHealthChangedDelegate.Broadcast(CurrentHealth, GetCurrentMaxHealth());
570	
571		// 蓝图事件
572		OnTakeDamage(ActualDamage);
573	
574		// 检查死亡
575		if (CurrentHealth <= 0)
576		{
577			HandleDeath();
578		}
579	}
