626	void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
627	{
628	    if (!Target || Target->bIsDead) return;
629	
630	    // 基础伤害计算
631	    int32 Damage = GetCurrentAttack();
632	
633	    // 伤害随机浮动（10% 范围）
634	    float RandomFactor = FMath::RandRange(0.9f, 1.1f);
635	    Damage = FMath::RoundToInt(Damage * RandomFactor);
636	
637	    // 应用伤害
638	    Target->TakeDamage(Damage);
639	
640	    // 消耗行动力
641	    ConsumeMovePoints(1);
642	}
