644	void ALFPTacticsUnit::HandleDeath()
645	{
646	    bIsDead = true;
647	
648		// 广播死亡事件
649	    OnDeathDelegate.Broadcast();
650	
651	    // 蓝图事件
652	    OnDeath();
653	
654	    // 通知 GameMode 敌方单位被击杀（掉落追踪）
655	    if (IsEnemy())
656	    {
657	        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
658	        {
659	            GM->OnEnemyUnitKilled(this);
660	        }
661	    }
662	
663	    // 从格子上移除
664	    ALFPHexTile* CurrentTile = GetCurrentTile();
665	    if (CurrentTile)
666	    {
667	        CurrentTile->SetUnitOnTile(nullptr);
668	    }
669	
670	    // 从回合系统中移除
671	    if (ALFPTurnManager* TurnManager = GetTurnManager())
672	    {
673	        TurnManager->UnregisterUnit(this);
674	    }
675	
676	    // 禁用碰撞
677	    SetActorEnableCollision(false);
678	
679	    // 延迟销毁
680	    FTimerHandle TimerHandle;
681	    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this]()
682	        {
683	            Destroy();
684	        }, 2.0f, false);
685	}
