717	ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
718	{
719	    // 获取所有玩家单位
720	    TArray<AActor*> PlayerUnits;
721	    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
722	
723	    ALFPTacticsUnit* BestTarget = nullptr;
724	    float BestThreatValue = -MAX_FLT;
725	
726	    for (AActor* Actor : PlayerUnits)
727	    {
728	        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
729	        if (Unit && Unit->IsAlive() && Unit->IsAlly())
730	        {
731	            float ThreatValue = CalculateThreatValue(Unit);
732	            if (ThreatValue > BestThreatValue)
733	            {
734	                BestThreatValue = ThreatValue;
735	                BestTarget = Unit;
736	            }
737	        }
738	    }
739	
740	    return BestTarget;
741	}
