743	ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
744	{
745	    ALFPHexGridManager* GridManager = GetGridManager();
746	    if (!GridManager)
747	    {
748	        return nullptr;
749	    }
750	    // 获取所有可移动位置
751	    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
752	
753	    ALFPHexTile* BestTile = nullptr;
754	    float BestPositionValue = -MAX_FLT;
755	
756	    for (ALFPHexTile* Tile : MovementRangeTiles)
757	    {
758	        // 跳过有单位的格子
759	        if (Tile->GetUnitOnTile()) continue;
760	
761	        float PositionValue = CalculatePositionValue(Tile, Target);
762	        if (PositionValue > BestPositionValue)
763	        {
764	            BestPositionValue = PositionValue;
765	            BestTile = Tile;
766	        }
767	    }
768	
769	    return BestTile;
770	}
