856	TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
857	{
858	    TArray<ALFPHexTile*> AttackRangeTiles;
859	
860	    if (ALFPHexGridManager* GridManager = GetGridManager())
861	    {
862	        // 近战攻击范围
863	        if (bMeleeAttack)
864	        {
865	            // 获取相邻格子
866	            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
867	            for (const FLFPHexCoordinates& Coord : Neighbors)
868	            {
869	                FLFPHexCoordinates Key(Coord.Q, Coord.R);
870	                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
871	                {
872	                    AttackRangeTiles.Add(Tile);
873	                }
874	            }
875	        }
876	        // 远程攻击范围
877	        else
878	        {
879	            // 获取攻击范围内的所有格子
880	            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
881	
882	            for (ALFPHexTile* Tile : TilesInRange)
883	            {
884	                AttackRangeTiles.Add(Tile);
885	            }
886	        }
887	    }
888	
889	    return AttackRangeTiles;
890	}
