892	bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
893	{
894	    if (!Target || !Target->GetCurrentTile()) return false;
895	
896	    // 计算距离
897	    int32 Distance = FLFPHexCoordinates::Distance(
898	        CurrentCoordinates,
899	        Target->GetCurrentCoordinates()
900	    );
901	
902	    // 近战攻击判定
903	    if (bMeleeAttack)
904	    {
905	        return Distance == 1; // 相邻格子
906	    }
907	    // 远程攻击判定
908	    else
909	    {
910	        return Distance >= 2 && Distance <= AttackRange;
911	    }
912	}
